import React, { createContext, useState, useRef, useContext, useEffect } from 'react';
import axios from 'axios';

const MusicContext = createContext();

export const MusicProvider = ({ children }) => {
  // --- STATE QUẢN LÝ NHẠC ---
  const [songs, setSongs] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentSong, setCurrentSong] = useState(null);
  
  // --- STATE QUẢN LÝ THỜI GIAN & YÊU THÍCH ---
  const [favorites, setFavorites] = useState([]);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);

  const audioRef = useRef(null);
  const user = JSON.parse(localStorage.getItem('user'));

  // 1. Lấy danh sách yêu thích khi khởi tạo
  useEffect(() => {
    const fetchFavorites = async () => {
      if (user) {
        try {
          const userId = user._id || user.id;
          const res = await axios.get(`http://localhost:5000/api/auth/${userId}/favorites`);
          setFavorites(res.data.map(song => song._id));
        } catch (err) {
          console.error("Lỗi lấy danh sách yêu thích:", err);
        }
      }
    };
    fetchFavorites();
  }, []);

  // 2. Logic tự động phát nhạc khi đổi bài
  useEffect(() => {
    if (currentSong && isPlaying && audioRef.current) {
      audioRef.current.play().catch(err => {
        console.error("Trình duyệt chặn tự động phát:", err);
        setIsPlaying(false);
      });
    }
  }, [currentSong]);

  // 3. Hàm kích hoạt phát nhạc
  const playMusic = (songList, index) => {
    if (!songList || songList.length === 0) return;
    setSongs(songList);
    setCurrentIndex(index);
    setCurrentSong(songList[index]);
    setIsPlaying(true);
  };

  // 4. Bật/Tạm dừng
  const togglePlay = () => {
    if (!currentSong) return;
    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      audioRef.current.play();
      setIsPlaying(true);
    }
  };

  // 5. Chuyển bài kế tiếp / Quay lại
  const handleNext = () => {
    if (songs.length === 0) return;
    const nextIndex = (currentIndex + 1) % songs.length;
    setCurrentIndex(nextIndex);
    setCurrentSong(songs[nextIndex]);
    setIsPlaying(true);
  };

  const handlePrev = () => {
    if (songs.length === 0) return;
    const prevIndex = (currentIndex - 1 + songs.length) % songs.length;
    setCurrentIndex(prevIndex);
    setCurrentSong(songs[prevIndex]);
    setIsPlaying(true);
  };

  // 6. XỬ LÝ THẢ TIM (QUAN TRỌNG: Đã thêm vào Provider)
  const toggleLike = async (songId) => {
    if (!user) return alert("Vui lòng đăng nhập để thả tim!");
    try {
      const userId = user._id || user.id;
      const res = await axios.post('http://localhost:5000/api/auth/toggle-favorite', {
        userId,
        songId
      });
      // Backend trả về mảng favorites mới, cập nhật vào state
      setFavorites(res.data.favorites);
    } catch (err) {
      console.error("Lỗi toggle favorite:", err);
    }
  };

  // 7. Cập nhật tiến trình nhạc
  const onTimeUpdate = () => {
    if (audioRef.current) {
      setCurrentTime(audioRef.current.currentTime);
    }
  };

  const onLoadedMetadata = () => {
    if (audioRef.current) {
      setDuration(audioRef.current.duration);
    }
  };

  // Hàm tua nhạc
  const seekTo = (percent) => {
    if (audioRef.current) {
      const time = (percent / 100) * audioRef.current.duration;
      audioRef.current.currentTime = time;
      setCurrentTime(time);
    }
  };

  // Xử lý URL an toàn cho tên file có dấu
  const getSafeUrl = (url) => {
    if (!url) return "";
    const baseUrl = "http://localhost:5000";
    const path = url.startsWith('/') ? url : `/${url}`;
    return encodeURI(`${baseUrl}${path}`);
  };

  return (
    <MusicContext.Provider value={{ 
      songs, currentSong, isPlaying, setIsPlaying, currentIndex, 
      audioRef, playMusic, togglePlay, handleNext, handlePrev,
      favorites, toggleLike, // Đã export toggleLike tại đây
      currentTime, duration, seekTo 
    }}>
      {children}
      
      {/* Thẻ audio ẩn xử lý phát nhạc toàn cục */}
      {currentSong && (
        <audio
          ref={audioRef}
          src={getSafeUrl(currentSong.songUrl || currentSong.musicUrl)}
          onTimeUpdate={onTimeUpdate}
          onLoadedMetadata={onLoadedMetadata}
          onEnded={handleNext}
        />
      )}
    </MusicContext.Provider>
  );
};

export const useMusic = () => {
  const context = useContext(MusicContext);
  if (!context) {
    throw new Error("useMusic must be used within a MusicProvider");
  }
  return context;
};
